queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?construction_workers a :Construction_Workers .
    ?construction_workers p:name ?name .
    ?construction_workers p:company_owner ?company_owner_f .
    FILTER(STR(?company_owner_f) = "Derek Brown")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?electricians a :Electricians .
    ?electricians p:name ?name .
    ?electricians p:company_owner ?company_owner_f .
    FILTER(STR(?company_owner_f) = "Derek Brown")
    BIND(?name AS ?o0)
  }
}

